"""
MKT Christ Commentary — Luke chapter 23
Run: python3 scripts/zc-christ-luke-23-23.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/commentary/mkt-christ/luke.json (existing v43, v46 preserved)

Key decisions in this range:
- Barabbas exchange (vv.18-25): read as substitutionary atonement in historical form — the guilty
  released, the innocent condemned; "son of the father" (bar-abba) irony is noted
- Triple innocence declaration (Pilate v.4, v.14-15; Herod v.15; the penitent thief v.41):
  together they establish Christ as Isa 53:9's sinless substitute
- Isa 53 citations across multiple verses (v.9 silence, v.12 numbered with transgressors,
  v.34 intercession for transgressors, v.9 burial by a rich man)
- Ps 22 citations: vv.11 mockery, v.34 garments by lot, v.35 save-yourself taunt
- Darkness (v.44): Amos 8:9 judgment-language applied to the cross
- Torn curtain (v.45): end of old covenant access-barrier; Heb 9:12 / 10:19-20 fulfillment
- Women as continuous witnesses (crucifixion → burial → empty tomb): Luke's apologetic
- v.53 "no one had been laid" echoes Luke 19:30 "no one had ever ridden" — same pattern
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge new entries without overwriting any existing verse
    # CHANGE? If output path changes, update load_comm/save_comm source arg
    # VERIFY: re-run; spot-check v34 (Ps 22:18 fulfillment), v45 (torn curtain), v50 (Isa 53:9)
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_23 = {
  "23": {
    "1": '<p>A direct fulfillment: the "whole assembly" (pan to pl&#275;thos, the full Sanhedrin) rising to deliver Jesus to Pilate enacts Psalm 2:2 — "the kings of the earth set themselves, and the rulers take counsel together against the LORD and his Anointed." The conspiring of king (Herod) and governor (Pilate) against the Messiah was foreordained (Acts 4:27-28 makes this explicit, reading Ps 2:1-2 as fulfilled in the passion); what appears as political process is the assembly of the nations against the Christ.</p>',
    "2": '<p>A revelation of God: the three charges against Jesus — subverting the nation, opposing payment of taxes to Caesar, claiming to be Christ the king — are all false as stated, yet each ironically identifies what he truly is. He is the Christ, he is a king, and his teaching does upend the existing social and religious order. The irony is Lukan: the Sanhedrin witnesses against Jesus truthfully while lying. The false accusation that condemns the innocent is the OT pattern of the righteous sufferer (Ps 35:11; Ps 27:12).</p>',
    "3": '<p>A direct revelation: Pilate\'s question "Are you the king of the Jews?" and Jesus\'s "You have said so" (sy legeis) is the Lukan equivalent of the trial before the Sanhedrin (22:70, "You say that I am"). The qualified affirmation acknowledges the title while reframing what it means: yes, king — but not the kind Pilate\'s question assumes. The Davidic kingship claim is the fulcrum of the passion narrative; the charge on the cross (v.38) will publicly declare what the trial confirms.</p>',
    "4": '<p>A direct fulfillment: Pilate\'s first declaration of innocence — "I find no basis for a charge against this man" — establishes Jesus as the sinless substitute of Isaiah 53:9 ("he had done no violence, and there was no deceit in his mouth"). The triple declaration across Pilate (vv.4, 14-15) and Herod (v.15) and the penitent thief (v.41) forms Luke\'s deliberate apologetic: the one condemned is juridically innocent. The condemnation of the innocent is the mechanism of the substitutionary exchange that the cross effects.</p>',
    "5": '<p>A theme: the accusation that Jesus "stirs up the people from Galilee to this place" recasts his ministry in political terms while unconsciously tracing the geography of the Servant\'s mission — Galilee of the Gentiles (Isa 9:1-2), where his ministry began, to Jerusalem, where it ends. The Galilean origin that was meant as a disqualification (John 7:52) is the divine design: the light that shone in Galilee\'s darkness has come to the center of Israel\'s life and is now being extinguished — and will rise again.</p>',
    "6": '<p>A theme: Pilate\'s discovery that Jesus is Galilean is the procedural step that sends him to Herod, fulfilling the pattern by which the suffering servant is passed from judgment to judgment. The geographic detail is also Christological: Galilee of the nations (Isa 9:1) sends its representative to Jerusalem\'s court — the light of the Gentiles now on trial before the covenant people\'s authorities.</p>',
    "7": '<p>A direct fulfillment: Herod the tetrarch — who had beheaded John the Baptist and sought to kill Jesus (Luke 13:31-32) — now receives Christ as his prisoner. The pattern of John\'s rejection and death being replicated in Jesus\'s is Lukan theology: "if they did this to the green tree, what will happen to the dry?" (v.31). Herod represents the Herodian dynasty that had long persecuted the prophets; before him now stands the one greater than all prophets (Luke 7:26-28).</p>',
    "8": '<p>A revelation of God: Herod\'s pleasure at seeing Jesus and his desire for a miracle-sign is the paradigmatic wrong response — spectator curiosity seeking entertainment rather than the repentance that Christ calls for. Jesus refused Herod\'s demand for a sign as he refused the Pharisees\' (Luke 11:29, "this generation seeks a sign but no sign will be given to it except the sign of Jonah"). The divine silence before the merely curious is itself a judgment: what Herod most needs (repentance) is precisely what he does not seek.</p>',
    "9": '<p>A direct fulfillment: "He plied him with many questions, but Jesus gave him no answer" — Isaiah 53:7 is enacted: "He was oppressed and afflicted, yet he opened not his mouth; like a lamb that is led to the slaughter, and like a sheep that before its shearers is silent, so he opened not his mouth." The Servant\'s silence before his accusers was not weakness but the fulfillment of the divine design. The word that made the world (John 1:3) holds his peace before a king, and the silence itself is the confrontation of divine holiness with human superficiality.</p>',
    "10": '<p>A theme: the chief priests and teachers of the law standing and "vehemently accusing" Jesus before Herod continues the pattern of Psalm 22:12-13 — "strong bulls of Bashan encircle me; they open wide their mouths at me, like a ravening and roaring lion." The Psalm of the righteous sufferer describes the passion with precision; Luke\'s account is the narrative enactment of what David foresaw.</p>',
    "11": '<p>A direct fulfillment: Herod and his soldiers ridiculing and mocking Jesus, dressing him in an elegant (lampra) robe, enacts Psalm 22:7-8 — "all who see me mock me; they make mouths at me, they wag their heads: He trusts in the LORD; let him deliver him." The magnificent robe is ironic royal investiture: the one dressed in mock-royal clothing is the true king. The mockery that fulfills the Psalm is the passion\'s bitter irony — the witnesses to his humiliation are witnesses to his kingship without knowing it.</p>',
    "12": '<p>A revelation of God: the unlikely political reconciliation of Herod and Pilate through their shared dismissal of Jesus is Luke\'s irony. Psalm 2:1-2 depicts the rulers of the earth conspiring together against the Lord\'s Anointed — and here two rivals become friends over the condemned Christ. The deeper irony is that the one whose condemnation unites enemies in hostility will, through that condemnation, ultimately unite hostilities in peace (Eph 2:14-16 — Christ breaks down the dividing wall, creating one new humanity).</p>',
    "13": '<p>A theme: Pilate assembles the complete trial of competing interests — chief priests, rulers, and the people — in a scene that mirrors the broad coalition of Psalm 2: kings, rulers, nations, and peoples conspiring against the LORD\'s Anointed. Luke\'s passion narrative is the Psalm 2 drama made historical. The court that should acquit (three times Pilate will declare innocence) becomes the instrument of condemnation — the justice system of the world unable to do justice to the just one.</p>',
    "14": '<p>A direct fulfillment: Pilate\'s second declaration — "I have examined him before you and found in him no basis for your charges against him" — advances the Isaianic innocence-motif. The Roman governor performing a legal examination and finding no crime rehearses what Isa 53:9 presupposes: the condemned one is innocent. That innocence is not incidental but essential to the atonement: only the sinless substitute can bear sin for others (2 Cor 5:21; Heb 4:15; 1 Pet 2:22).</p>',
    "15": '<p>A direct fulfillment: Herod\'s concurrence ("neither has Herod") completes the two-witness requirement of Deuteronomy 19:15 for establishing legal innocence — ironically, the two witnesses required by law to establish a charge are instead the two who establish innocence. The triple declaration (Pilate, Herod, the penitent thief) frames the crucifixion as the execution of the innocent by judicial murder — which is precisely the mechanism of substitutionary atonement: the guilty go free because the innocent is condemned.</p>',
    "16": '<p>A theme: Pilate\'s proposed compromise — punish (paideusas) and release — already enacts a form of vicarious suffering. The innocent man is punished to satisfy the crowd\'s demand, even before the formal death sentence. The logic anticipates the cross: Christ is punished though no crime is found in him. Isaiah 53:5 describes the Servant\'s punishment: "he was pierced for our transgressions; he was crushed for our iniquities; upon him was the chastisement that brought us peace."</p>',
    "17": '<p>A theme: the Passover prisoner-release custom (attested in the Gospels though not clearly in extrabiblical sources) is the historical mechanism that makes the Barabbas exchange possible. The Passover context is significant: the feast that commemorates deliverance through a substituted death (the lamb) now provides the historical occasion for the ultimate substituted death. The custom creates the dramatic structure within which the Gospel-exchange (guilty released, innocent condemned) becomes visible.</p>',
    "18": '<p>A direct fulfillment: "Release Barabbas to us!" The Barabbas exchange is the substitutionary atonement in historical dramatic form. Bar-abba in Aramaic means "son of the father" — and the crowd releases the guilty "son of the father" while condemning the true Son of the Father. Barabbas had been imprisoned for insurrection and murder (v.19) — the exact crimes of which Jesus was falsely accused. The innocent one takes the place of the guilty one; the condemned criminal walks free because the condemned Christ takes his sentence. This is 2 Cor 5:21 enacted: "him who knew no sin he made to be sin for us, so that in him we might become the righteousness of God."</p>',
    "19": '<p>A theme: Barabbas\'s crimes — insurrection (stasis) and murder — are precisely the charges the Sanhedrin laid against Jesus (v.2, "subverting our nation"; the implicit charge in "king"). The inversion is complete: the actual insurrectionist goes free; the one falsely accused of insurrection is condemned. The guilty bears none of his own guilt; the innocent bears all of it. Luke presents the details with a historian\'s precision and a theologian\'s intent.</p>',
    "20": '<p>A revelation of God: Pilate\'s repeated attempts to release Jesus show that human authority, even when it knows the right, cannot always do it in the face of crowd pressure. The world\'s systems of justice fail before the demands of the mob — yet within this failure the divine purpose advances. The one who could have called twelve legions of angels (Matt 26:53) is handed over by a man who knows he is innocent; the Father allows the injustice as the appointed means of the world\'s redemption.</p>',
    "21": '<p>A direct fulfillment: "Crucify him! Crucify him!" — the crowd\'s demand for crucifixion enacts Psalm 22:16, "they pierce my hands and my feet." The specific form of death — crucifixion, which the Psalm describes centuries before it was practiced in Judea — was prefigured in the lament of the righteous sufferer. The crowd\'s choice of method is the unwitting fulfillment of the ancient script; they accomplish what the Psalm foresaw without knowing the Psalm existed.</p>',
    "22": '<p>A direct revelation: Pilate\'s third question — "Why? What crime has this man committed?" — and his third declaration of innocence drive the point home: no one can answer the question. The condemnation has no legal basis; it is pure injustice. Yet within this injustice the deepest justice is being enacted — the just dying for the unjust (1 Pet 3:18). The very absence of a justifying crime makes clear that the death is substitutionary, not punitive for his own wrongdoing.</p>',
    "23": '<p>A theme: "their shouts prevailed" — the voice of the crowd overrules the voice of justice. The world\'s decision about Jesus (rejected, condemned, crucified) is the decision that the cross transforms into the world\'s salvation. What the crowd demands as punishment becomes, through the divine purpose, the instrument of their rescue. Acts 3:15-19 will make this explicit: "You killed the Author of life... but God raised him from the dead; to this we are witnesses."</p>',
    "24": '<p>A revelation of God: Pilate\'s decision to grant the crowd\'s demand is simultaneously the moment of human injustice and divine appointment. Luke uses the same language of "giving/handing over" (paredōken) that describes Judas\'s betrayal (22:6) and God\'s handing over of his Son (Rom 8:32, "he did not spare his own Son but gave him up for us all"). The chain of human decisions — Judas, Sanhedrin, Herod, Pilate, the crowd — is the historical medium through which the divine plan of atonement is executed.</p>',
    "25": '<p>A direct fulfillment: "He released the man who had been thrown into prison for insurrection and murder... and surrendered Jesus to their will." The exchange is complete. The guilty is released; the innocent is surrendered (paredōken). This is the substitution that Isaiah 53 described: "he bore the sin of many, and makes intercession for the transgressors" — and in this moment, the transgressors go free while the sinless one goes to execution. The passion narrative has arrived at the center of the Gospel.</p>',
    "26": '<p>A theme: Simon of Cyrene compelled to carry the cross of the condemned one is both a historical detail and a shadow of discipleship. Luke alone of the Synoptists says Simon bore the cross "behind Jesus" (opisth&#275; Iesou) — the language of following (Luke 9:23, "take up your cross daily and follow me"). The foreigner from Cyrene (North Africa) who carries the cross of Christ anticipates the Gentile mission: those from the ends of the earth will take up what was laid on Jesus and follow him. Simon carries the cross; Christ bears what the cross means.</p>',
    "27": '<p>A revelation of God: the large number of women who followed, mourning and lamenting, fulfill the pattern of Zechariah 12:10-12 — "they will look on me, the one they have pierced, and they will mourn for him as one mourns for an only child." These women of Jerusalem represent the faithful remnant of Israel who receive the passion not with triumphalism but with grief — a grief that the risen Christ will transform into witness. Their mourning is the appropriate human response to the death of the sinless one.</p>',
    "28": '<p>A direct prophecy: Jesus turns to the lamenting women and redirects their mourning — "weep for yourselves and for your children." The coming judgment on Jerusalem (21:20-24) will be worse than his death; his death is the event that would have been Israel\'s rescue if received in faith. The turn from compassion for himself to prophetic warning for others is the Servant\'s characteristic movement: even in his dying, Christ thinks of others rather than himself, and his last public words before the cross are prophetic intercession and warning.</p>',
    "29": '<p>A direct fulfillment: the time coming when barren women are blessed echoes Hosea 9:10-14 (God\'s judgment making Israel\'s womb barren as a sign of covenant rejection) and Jeremiah 16:2-4 (Jeremiah forbidden to have children as a sign of coming judgment). The reversal of the blessing on fruitfulness signals eschatological disaster — when the judgment comes, the mercy of childlessness will be envied. The one who warns of this is the one whose rejection triggers it; Christ\'s prophecy frames his own death as the decisive rejection-moment.</p>',
    "30": '<p>A direct citation: "they will say to the mountains, Fall on us! and to the hills, Cover us!" is a direct quotation of Hosea 10:8 (the judgment on Samaria applied now to Jerusalem). The same words appear in Revelation 6:16 ("they called to the mountains and rocks, Fall on us and hide us from the face of him who is seated on the throne, and from the wrath of the Lamb"). Luke 23:30 thus connects the fall of Jerusalem to the final judgment of the Lamb — the one rejected at the cross returns as the judge before whom the nations cry for concealment.</p>',
    "31": '<p>A revelation of God: "if they do these things when the tree is green, what will happen when it is dry?" — the proverb draws on the green/dry tree imagery of the OT (Ezek 20:47) applied to Israel\'s judgment. The "green tree" is Christ himself: if the Romans execute the innocent one with the fullness of life, what will they do to the guilty nation dried up by covenant unfaithfulness? The proverb is also Christological: Christ is the living tree whose death gives life, but without the tree\'s life, Israel cannot survive the judgment.</p>',
    "32": '<p>A direct fulfillment: "two other men, both criminals, were also led out with him to be executed" — the fulfillment of Isaiah 53:12, "he was numbered with the transgressors." This is the verse Jesus himself cited in Luke 22:37 ("this scripture must be fulfilled in me"). The precise fulfillment begins here: he is led out and crucified between two criminals, numbered with the guilty. The prophet\'s word, spoken seven centuries earlier, is enacted in the specific circumstances of his death.</p>',
    "33": '<p>A direct fulfillment: the crucifixion at the Place of the Skull is the moment Psalm 22:16 is accomplished — "they pierce my hands and my feet." The Psalm of the righteous sufferer, which David wrote as a cry of dereliction, is now the narrative of the Son of David\'s death. The one who cited Psalm 22 at the beginning of the passion (Luke 22:37, citing Isa 53) is now at its center. The criminals crucified with him complete the Isaiah 53:12 fulfillment (numbered with transgressors) even as the Psalm 22 fulfillment begins.</p>',
    "34": '<p>A direct fulfillment: the first word from the cross — "Father, forgive them, for they do not know what they are doing" — enacts Isaiah 53:12, "he bore the sin of many, and makes intercession for the transgressors." Christ dies as the Servant-Intercessor, praying for the very ones who are killing him. The garments divided by lot fulfill Psalm 22:18 ("they divide my garments among them and for my clothing they cast lots") with literal precision — Luke presents the soldiers\' gambling as the unwitting enactment of the ancient Psalm. The intercession and the lot-casting happen simultaneously: the Servant-prayer and the Psalm-fulfillment coincide.</p>',
    "35": '<p>A direct fulfillment: the rulers\' taunt — "He saved others; let him save himself, if he is the Christ of God, the Chosen One" — enacts Psalm 22:8, "He trusts in the LORD; let him deliver him, let him rescue him, for he delights in him." The mockers quote the Psalm without knowing it, turning scripture against the one who fulfills scripture. The bitter irony is the Gospel: he cannot save others AND save himself — the salvation of others is accomplished precisely through not saving himself. The Chosen One\'s election to suffering is the instrument of his election to save.</p>',
    "36": '<p>A direct fulfillment: the soldiers offering sour wine (oxos) fulfills Psalm 69:21 — "for my thirst they gave me sour wine to drink." Psalm 69, the great lament psalm of the righteous sufferer who is hated without cause and bears the reproaches of those who reproach God, provides the second Psalm-framework for the passion alongside Psalm 22. Together these two psalms — the abandonment cry (Ps 22) and the community-reproach lament (Ps 69) — provide the scriptural matrix that the earliest church used to interpret and proclaim the crucifixion.</p>',
    "37": '<p>A revelation of God: the soldiers\' taunt — "if you are the king of the Jews, save yourself" — mirrors the devil\'s third temptation in the wilderness (Luke 4:9-11, "throw yourself down and the angels will catch you"). The test is identical: prove your identity by a spectacular rescue from danger. Christ refused the temptation in the wilderness because the way of the cross was the Father\'s appointed way; he refuses it again at the cross because his kingship is expressed through self-giving, not self-preservation. The king who could save himself chooses the path that saves others instead.</p>',
    "38": '<p>A direct revelation: the written notice — "This is the King of the Jews" — is the inadvertent proclamation of the Gospel. Pilate writes as mockery what Luke presents as truth: Jesus is the King of the Jews, and in dying as their rejected king, he becomes the king of all who receive him. The superscription in multiple languages (John 19:20 adds Greek and Latin) makes the universal proclamation: what was intended as a shame-inscription is the first Gentile proclamation of the Messianic kingship.</p>',
    "39": '<p>A revelation of God: the impenitent criminal\'s taunt — "Aren\'t you the Messiah? Save yourself and us!" — is the demand for a miraculous rescue as proof of identity. It is the wrong request (escape from consequences of guilt) in place of the right one (forgiveness from guilt itself). The penitent thief\'s response (v.40-42) shows the contrast: the one who fears God recognizes that rescue from punishment is not what is needed but rescue from the punishment that guilt has earned. The two criminals dramatize the two responses to the crucified Christ.</p>',
    "40": '<p>A revelation of God: "Don\'t you fear God, since you are under the same sentence?" — the penitent thief\'s rebuke begins with the fear of God, which is "the beginning of wisdom" (Ps 111:10; Prov 9:10). Precisely this fear — recognizing divine justice and divine authority — distinguishes the two criminals. The one who fears God is able to see clearly: their guilt is real, their punishment is just, and the man dying beside them is innocent. Fear of God is the precondition for recognizing the Christ.</p>',
    "41": '<p>A direct fulfillment: "this man has done nothing wrong" — the penitent thief becomes the third human witness (alongside Pilate\'s double declaration and Herod\'s concurrence) to Christ\'s innocence, now from the perspective of one who is himself dying under just punishment. His declaration fulfills Isaiah 53:9 ("no violence" and "no deceit in his mouth") from the most unexpected witness: a condemned criminal, with no theological training, who simply observes the one dying beside him and sees the truth that the religious authorities refused to see.</p>',
    "42": '<p>A direct revelation: "Jesus, remember me when you come into your kingdom" — the penitent thief\'s request is a confession of faith in the resurrection and parousia addressed to a dying man. "Remember me" is the language of covenant-plea (Neh 5:19; 13:14 — "remember me, O my God"), asking to be included in the beneficent attention of the covenant God. The dying criminal confesses what the Sanhedrin denied: that this condemned man has a kingdom to come into. The thief\'s faith is the simplest and most complete Christological confession in the Gospel.</p>',
    "44": '<p>A direct fulfillment: the darkness from noon until three in the afternoon fulfills Amos 8:9 — "And on that day, declares the Lord GOD, I will make the sun go down at noon and darken the earth in broad daylight." Amos\'s oracle of divine judgment, originally addressed to Israel\'s festive day turned to mourning, is now enacted at the moment the Messiah bears the sin of the world. The cosmic darkness signals that the cross is not merely a Roman execution but a divine event — the moment of divine judgment upon sin, borne by the sinless one for the guilty.</p>',
    "45": '<p>A direct fulfillment: the curtain of the temple torn in two at Christ\'s death is the most theologically dense event in the passion narrative. The curtain (katapetasma) separated the Holy of Holies from the rest of the sanctuary (Exod 26:31-33) — the barrier between the presence of God and the sinful people, bridgeable only by the high priest once a year on the Day of Atonement (Lev 16). Its tearing at the moment of Christ\'s death declares that the barrier is permanently removed: what the Day of Atonement enacted annually, Christ\'s sacrifice accomplishes once for all (Heb 9:12; 10:19-20). The way into the presence of God is now open, not through the blood of bulls and goats but through the blood of Christ.</p>',
    "47": '<p>A revelation of God: the centurion\'s response — "surely this was a righteous man" (dikaios) — is the first Gentile confession in Luke\'s passion narrative. The Roman soldier who supervised the execution is the first to honor the crucified Christ, anticipating the Gentile mission of Acts. His word dikaios (righteous) fulfills Isaiah 53:11: "my righteous servant will justify many" — the Servant who is declared righteous even at his death becomes the source of righteousness for others. The centurion\'s confession is the seed of what Paul will say: "Christ died for us" (Rom 5:8).</p>',
    "48": '<p>A revelation of God: the crowd who had cried "crucify him!" now beats their breasts — the gesture of mourning and self-condemnation in Second Temple Judaism. Luke\'s observation is the beginning of the transformation that Acts will narrate: the same crowd that condemned Christ will be "cut to the heart" (Acts 2:37) and ask "what shall we do?" The cross does not end the story of Israel\'s engagement with Christ; it creates the conditions for the mass repentance of Pentecost. The beating of breasts at Golgotha and the piercing of hearts at Pentecost are the same movement of conviction.</p>',
    "49": '<p>A theme: the disciples and the Galilean women who "stood at a distance watching" fulfill Psalm 38:11 — "my friends and companions stand aloof from my plague, and my nearest kin stand far off." The pattern of the righteous sufferer abandoned by his intimates at the point of greatest suffering is now the experience of Christ. Yet Luke\'s note about the women standing and watching is his apologetic setup: these same women (v.55) will see the tomb, note how his body is laid, and return to find it empty (24:1-3). Their witness is continuous from crucifixion to resurrection.</p>',
    "50": '<p>A direct fulfillment: Joseph of Arimathea — "a good and upright man," a member of the Council — is the fulfillment of Isaiah 53:9, "he made his grave with the wicked and with a rich man in his death." The Servant\'s burial by a wealthy, righteous man is a detail the Isaiah prophecy specified; Luke\'s account preserves it. Joseph is also "waiting for the kingdom of God" (v.51) — the faithful remnant within the leadership that the Sanhedrin majority represented. The Servant\'s burial is an act of covenant faithfulness against the grain of the majority verdict.</p>',
    "51": '<p>A revelation of God: Joseph "had not consented to their decision and action" — even within the court that condemned Christ, a dissenting voice. Luke preserves this detail to show that the Sanhedrin\'s decision was not unanimous and that within Israel\'s leadership there were those who received the kingdom of God differently from those who rejected it. Joseph represents the remnant theology that runs from Isaiah through the Gospels: within the apostate majority, God preserves those who wait for his redemption.</p>',
    "52": '<p>A theme: Joseph approaching Pilate to ask for Christ\'s body is an act of courageous covenant loyalty. Jewish burial law required that bodies not be left exposed — to leave a crucified man hanging was Gentile practice; the Torah prescribed burial even for the executed (Deut 21:22-23). Joseph\'s request enacts the Torah\'s demand for dignified burial of the condemned, and in doing so he places the body of the crucified Christ in an honorable tomb rather than the common criminals\' pit — precisely fulfilling Isaiah 53:9\'s "with a rich man in his death."</p>',
    "53": '<p>A direct fulfillment: "placed in a tomb cut in the rock, one in which no one had yet been laid" completes the Isaiah 53:9 fulfillment (burial with the rich) while adding a detail Luke also used for the borrowed donkey (Luke 19:30, "on which no one has ever yet sat"). The unridden donkey carried the king into Jerusalem; the unlaid tomb will hold — briefly — the king of creation. The virgin tomb is the vessel of the firstfruits resurrection: as a first-fruits offering was the first and therefore consecrated, Christ is the first to rise bodily from this tomb, the firstborn from the dead (Col 1:18).</p>',
    "54": '<p>A theme: "It was Preparation Day, and the Sabbath was about to begin" — the chronological notation establishes that Christ dies on the day of preparation for the Sabbath (14 Nisan, when the Passover lambs were slaughtered) and lies in the tomb on the seventh day of rest. The Passover-Sabbath-resurrection pattern encodes the Gospel in Israel\'s calendar: the Lamb slaughtered on Preparation Day, resting in the tomb on the Sabbath, rising on the first day of the new creation week (24:1). The entire Mosaic liturgical calendar finds its fulfillment in the three days of the passion.</p>',
    "55": '<p>A revelation of God: the Galilean women who had followed from the beginning of Christ\'s ministry are now the eyewitnesses who link crucifixion to burial — "they saw the tomb and how his body was laid in it." Their continuous presence (crucifixion, v.49; burial, v.55; empty tomb, 24:1-3) is Luke\'s apologetic for the resurrection: the same witnesses who saw him die and saw where he was buried are the ones who will find the tomb empty and hear "he is not here; he has risen" (24:6). The resurrection\'s credibility rests on this continuity of testimony.</p>',
    "56": '<p>A revelation of God: the women "prepared spices and perfumes" — an act of burial love intended to honor the dead body — and rested on the Sabbath "in obedience to the commandment." Their Torah-faithfulness honors both the law and the one they love; but their intended anointing is rendered unnecessary by the resurrection. The women who sought to anoint the dead Christ will instead receive the proclamation of the risen Christ. Their Sabbath rest is the last Sabbath before the new creation begins; when they rise on the first day (24:1), they enter the world of the resurrection, where the old Sabbath\'s anticipation has been permanently fulfilled.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_23)
    save_comm('mkt-christ', 'luke', existing)
    ch23_count = len(existing.get('23', {}))
    print(f'Luke 23 mkt-christ: {ch23_count} verses written.')

if __name__ == '__main__':
    main()
